from dataclasses import dataclass, field
from collections import defaultdict
import statistics


@dataclass
class RoundReport:
    round_number: int
    system_prompt_version: str
    sessions: list[WoZSession]

    def total_issues(self) -> int:
        return sum(s.issue_count() for s in self.sessions)

    def completion_rate(self) -> float:
        completed = sum(1 for s in self.sessions if s.task_completed)
        return completed / len(self.sessions) if self.sessions else 0.0

    def issue_frequency_by_section(self) -> dict[str, int]:
        freq: dict[str, int] = defaultdict(int)
        for session in self.sessions:
            for note in session.notes:
                freq[note.prompt_section] += 1
        return dict(sorted(freq.items(), key=lambda x: x[1], reverse=True))

    def is_ready_to_advance(self) -> bool:
        """Advance to engineering if ≤ 2 total issues across all sessions."""
        return self.total_issues() <= 2

    def prompt_deltas(self) -> list[str]:
        """Unique set of suggested prompt changes across all sessions."""
        seen: set[str] = set()
        deltas: list[str] = []
        for session in self.sessions:
            for note in session.notes:
                delta = note.to_delta()
                if delta not in seen:
                    seen.add(delta)
                    deltas.append(delta)
        return deltas

    def summary(self) -> str:
        return (
            f"Round {self.round_number} | v{self.system_prompt_version} | "
            f"{len(self.sessions)} participants | "
            f"{self.total_issues()} issues | "
            f"completion={self.completion_rate():.0%} | "
            f"{'ADVANCE' if self.is_ready_to_advance() else 'REVISE'}"
        )

def gate_check(report: RoundReport) -> tuple[bool, list[str]]:
    """Returns (passed, list_of_failures). All must pass to advance."""
    failures: list[str] = []

    if report.completion_rate() < 0.80:
        failures.append(
            f"Completion rate {report.completion_rate():.0%} < 80%"
        )

    if report.total_issues() > 2:
        failures.append(
            f"Total issues {report.total_issues()} > 2"
        )

    critical_types = {IssueType.REFUSAL_MISS, IssueType.ABANDONMENT}
    for session in report.sessions:
        for note in session.notes:
            if note.issue_type in critical_types:
                failures.append(
                    f"Critical issue: {note.issue_type.value} in session {session.session_id} "
                    f"turn {note.turn_number}"
                )

    return len(failures) == 0, failures
